"use client";

import { useState, useRef, useEffect } from "react";
import { useMe, useUpdateMe } from "@/hooks/useUsers";
import { useOwnHub, useUpdateOwnHub } from "@/hooks/useHubs";
import { onboardingApi } from "@/lib/api/Onboarding";
import { Camera, Loader2, Check, X } from "lucide-react";
import { cn } from "@/lib/utils";
import type { UserResponse } from "@/types/users";
import { toast } from "sonner";

export default function SettingsPage() {
  const { data: me } = useMe();

  if (!me) {
    return (
      <main className="min-h-screen bg-[#FBF8FF] flex items-center justify-center">
        <Loader2 className="w-5 h-5 animate-spin text-[#A08DBE]" />
      </main>
    );
  }

  return <SettingsForm me={me} />;
}

function SettingsForm({ me }: { me: UserResponse }) {
  const { mutate: updateMe, isPending: savingMe } = useUpdateMe();

  const [fullName, setFullName] = useState(me.full_name ?? "");
  const [username, setUsername] = useState(me.username ?? "");
  const [bio, setBio] = useState(me.bio ?? "");
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);

  const [usernameAvailable, setUsernameAvailable] = useState<boolean | null>(
    null,
  );
  const [checkingUsername, setCheckingUsername] = useState(false);

  const avatarRef = useRef<HTMLInputElement>(null);

  // ── Username availability check ──────────────────────────────────────────
  useEffect(() => {
    const trimmed = username.trim();

    if (trimmed === me.username || trimmed.length < 3) {
      setUsernameAvailable(null);
      return;
    }

    setCheckingUsername(true);
    const timer = setTimeout(async () => {
      try {
        const res = await onboardingApi.checkUsername(trimmed);
        setUsernameAvailable(res.available);
      } finally {
        setCheckingUsername(false);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [username, me.username]);

  const avatarSrc = avatarPreview ?? 
  (me.avatar_url ? `${process.env.NEXT_PUBLIC_API_URL}${me.avatar_url}` : null);
  const initials = (me.full_name ?? me.username ?? "?").charAt(0).toUpperCase();

  const handleAvatarChange = (f: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      setAvatarPreview(e.target?.result as string);
    };
    reader.readAsDataURL(f);
  };

  const isDirty =
    fullName !== (me.full_name ?? "") ||
    username !== (me.username ?? "") ||
    bio !== (me.bio ?? "") ||
    avatarPreview !== null;

  const canSave =
    isDirty && !savingMe && usernameAvailable !== false && !checkingUsername;

  const handleSave = () => {
    updateMe(
      {
        full_name: fullName.trim() || undefined,
        username: username.trim() || undefined,
        bio: bio.trim() || undefined,
        avatar_url: avatarPreview ?? undefined,
      },
      {
        onSuccess: () => toast.success("Profile updated"),
        onError: () => toast.error("Failed to save changes"),
      },
    );
  };

  return (
    <main className="min-h-screen bg-[#FBF8FF] px-5 py-8 lg:px-9 lg:py-10">
      <div className="max-w-[520px] mx-auto">
        <div className="mb-7">
          <h1 className="text-[22px] font-bold text-[#2D0052]">Settings</h1>
          <p className="text-[13px] text-[#A08DBE] mt-0.5">
            Manage your profile information
          </p>
        </div>

        <div className="flex flex-col gap-4">
          {/* Avatar card */}
          <div
            className="bg-white rounded-2xl border border-[#EDE5F8] px-6 py-5"
            style={{ boxShadow: "0 1px 4px rgba(45,0,82,0.05)" }}
          >
            <p className="text-[11px] font-bold uppercase tracking-[0.1em] text-[#A08DBE] mb-4">
              Profile photo
            </p>
            <div className="flex items-center gap-5">
              <div
                className="relative group cursor-pointer shrink-0"
                onClick={() => avatarRef.current?.click()}
              >
                <div
                  className="w-[72px] h-[72px] rounded-[16px] overflow-hidden flex items-center justify-center"
                  style={{
                    background: avatarSrc ? "transparent" : "#8A2BE2",
                    border: "2px solid #EDE5F8",
                    boxShadow: "0 2px 10px rgba(45,0,82,0.12)",
                  }}
                >
                  {avatarSrc ? (
                    <img
                      src={avatarSrc}
                      alt="Avatar"
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <span className="text-white text-[26px] font-bold select-none">
                      {initials}
                    </span>
                  )}
                </div>
                <div
                  className="absolute inset-0 rounded-[16px] flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all"
                  style={{ background: "rgba(45,0,82,0.5)" }}
                >
                  <Camera className="w-5 h-5 text-white" />
                </div>
                <input
                  ref={avatarRef}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={(e) => {
                    const f = e.target.files?.[0];
                    if (f) handleAvatarChange(f);
                  }}
                />
              </div>

              <div>
                <p className="text-[13px] font-semibold text-[#2D0052]">
                  {avatarPreview ? "New photo selected" : "Upload a photo"}
                </p>
                <p className="text-[12px] text-[#A08DBE] mt-0.5">
                  JPG or PNG · Recommended 400×400
                </p>
                <button
                  onClick={() => avatarRef.current?.click()}
                  className="mt-2 text-[12px] font-semibold text-[#8A2BE2] underline underline-offset-2 hover:text-[#7722CC] transition-colors"
                >
                  Choose photo
                </button>
              </div>
            </div>
          </div>

          {/* Profile fields card */}
          <div
            className="bg-white rounded-2xl border border-[#EDE5F8] px-6 py-5"
            style={{ boxShadow: "0 1px 4px rgba(45,0,82,0.05)" }}
          >
            <p className="text-[11px] font-bold uppercase tracking-[0.1em] text-[#A08DBE] mb-4">
              Profile info
            </p>
            <div className="flex flex-col gap-4">
              <Field
                label="Full name"
                value={fullName}
                onChange={setFullName}
                placeholder="Your display name"
              />

              <Field
                label="Username"
                value={username}
                onChange={setUsername}
                placeholder="yourhandle"
                prefix="@"
                suffix={
                  checkingUsername ? (
                    <Loader2 className="w-3.5 h-3.5 animate-spin text-[#A08DBE]" />
                  ) : usernameAvailable === true ? (
                    <Check className="w-3.5 h-3.5 text-[#16A34A]" />
                  ) : usernameAvailable === false ? (
                    <X className="w-3.5 h-3.5 text-red-400" />
                  ) : null
                }
                hint={
                  usernameAvailable === false ? "Username is taken" : undefined
                }
              />

              <div>
                <label className="block text-[11px] font-bold uppercase tracking-[0.1em] text-[#A08DBE] mb-1.5">
                  Bio
                </label>
                <textarea
                  value={bio}
                  onChange={(e) => setBio(e.target.value)}
                  placeholder="Tell subscribers a bit about yourself…"
                  rows={3}
                  maxLength={500}
                  className="w-full bg-[#FBF8FF] border border-[#EDE5F8] rounded-[10px] px-4 py-2.5 text-[13.5px] text-[#2D0052] placeholder:text-[#C4B5D4] outline-none focus:border-[#A78BFA] focus:ring-2 focus:ring-[#8A2BE2]/10 transition-all resize-none"
                />
                <p className="text-right text-[11px] text-[#C4B5D4] mt-1">
                  {bio.length}/500
                </p>
              </div>
            </div>
          </div>

          {/* Save */}
          <button
            onClick={handleSave}
            disabled={!canSave}
            className={cn(
              "w-full py-3 rounded-[12px] text-[13.5px] font-bold transition-all flex items-center justify-center gap-2",
              canSave ? "text-white" : "text-white/60 cursor-not-allowed",
            )}
            style={{
              background: canSave ? "#8A2BE2" : "rgba(138,43,226,0.35)",
              boxShadow: canSave ? "0 4px 14px rgba(138,43,226,0.35)" : "none",
            }}
          >
            {savingMe && <Loader2 className="w-4 h-4 animate-spin" />}
            {savingMe ? "Saving…" : "Save changes"}
          </button>
        </div>
      </div>
    </main>
  );
}

// ─── Field ────────────────────────────────────────────────────────────────────
function Field({
  label,
  value,
  onChange,
  placeholder,
  prefix,
  suffix,
  hint,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  prefix?: string;
  suffix?: React.ReactNode;
  hint?: string;
}) {
  return (
    <div>
      <label className="block text-[11px] font-bold uppercase tracking-[0.1em] text-[#A08DBE] mb-1.5">
        {label}
      </label>
      <div className="relative">
        {prefix && (
          <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-[13.5px] text-[#A08DBE] font-medium select-none">
            {prefix}
          </span>
        )}
        <input
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          className={cn(
            "w-full bg-[#FBF8FF] border rounded-[10px] py-2.5 text-[13.5px] text-[#2D0052] placeholder:text-[#C4B5D4] outline-none focus:ring-2 focus:ring-[#8A2BE2]/10 transition-all",
            prefix ? "pl-8" : "px-4",
            suffix ? "pr-9" : "pr-4",
            hint
              ? "border-red-300 focus:border-red-400"
              : "border-[#EDE5F8] focus:border-[#A78BFA]",
          )}
        />
        {suffix && (
          <span className="absolute right-3 top-1/2 -translate-y-1/2">
            {suffix}
          </span>
        )}
      </div>
      {hint && <p className="text-[11.5px] text-red-400 mt-1">{hint}</p>}
    </div>
  );
}
